#include <iostream>
#include <fstream>
#include <string>
#include <vector>

struct PlayerData {
    std::string name;
    int health;
    int attack;
    int defense;
};

int main() {
    std::cout << "=== File I/O Basics — fstream ===" << std::endl;

    // 1. Writing to a file
    std::cout << "\n--- Writing to file ---" << std::endl;
    std::ofstream outFile("player.txt");

    if (outFile.is_open()) {
        outFile << "Hero 100 20 15" << std::endl;
        outFile << "Aragorn 120 25 18" << std::endl;
        outFile << "Gandalf 80 15 10" << std::endl;

        outFile.close();
        std::cout << "✅ File written successfully!" << std::endl;
    } else {
        std::cout << "❌ Failed to open file for writing!" << std::endl;
    }

    // 2. Reading from a file
    std::cout << "\n--- Reading from file ---" << std::endl;
    std::ifstream inFile("player.txt");

    if (inFile.is_open()) {
        std::string line;
        while (std::getline(inFile, line)) {
            std::cout << "Read: " << line << std::endl;
        }
        inFile.close();
    } else {
        std::cout << "❌ Failed to open file for reading!" << std::endl;
    }

    // 3. Appending to a file
    std::cout << "\n--- Appending to file ---" << std::endl;
    std::ofstream appendFile("player.txt", std::ios::app);

    if (appendFile.is_open()) {
        appendFile << "Legolas 90 18 12" << std::endl;
        appendFile.close();
        std::cout << "✅ Appended successfully!" << std::endl;
    }

    // 4. Reading file with formatted input
    std::cout << "\n--- Reading with formatted input ---" << std::endl;
    std::ifstream dataFile("player.txt");

    if (dataFile.is_open()) {
        std::vector<PlayerData> players;
        PlayerData p;

        while (dataFile >> p.name >> p.health >> p.attack >> p.defense) {
            players.push_back(p);
        }

        std::cout << "Players loaded:" << std::endl;
        for (const auto& player : players) {
            std::cout << "  " << player.name 
                      << " (HP: " << player.health 
                      << ", ATK: " << player.attack 
                      << ", DEF: " << player.defense << ")" << std::endl;
        }

        dataFile.close();
    }

    // 5. File modes
    std::cout << "\n--- File Modes ---" << std::endl;
    std::cout << "std::ios::out  — write (overwrites)" << std::endl;
    std::cout << "std::ios::in   — read" << std::endl;
    std::cout << "std::ios::app  — append" << std::endl;
    std::cout << "std::ios::ate  — append to end" << std::endl;
    std::cout << "std::ios::trunc — truncate (default for out)" << std::endl;

    // 6. Checking file status
    std::cout << "\n--- File Status ---" << std::endl;
    std::ifstream checkFile("nonexistent.txt");

    if (checkFile) {
        std::cout << "✅ File exists!" << std::endl;
    } else {
        std::cout << "❌ File does not exist!" << std::endl;
    }
    checkFile.close();

    std::cout << "\n--- File I/O Methods ---" << std::endl;
    std::cout << "✅ ofstream — output (write)" << std::endl;
    std::cout << "✅ ifstream — input (read)" << std::endl;
    std::cout << "✅ fstream — both" << std::endl;

    return 0;
}

