#include <iostream>
#include <fstream>
#include <string>

struct Item {
    std::string name;
    int value;
    int weight;
};

int main() {
    std::cout << "=== Inventory File I/O ===" << std::endl;

    // Write
    std::ofstream outFile("inventory.txt");
    if (outFile.is_open()) {
        outFile << "Sword 50 3" << std::endl;
        outFile << "Shield 40 5" << std::endl;
        outFile << "Potion 25 1" << std::endl;
        outFile.close();
        std::cout << "✅ Written inventory" << std::endl;
    }

    // Read
    std::ifstream inFile("inventory.txt");
    if (inFile.is_open()) {
        Item item;
        std::cout << "\n--- Inventory ---" << std::endl;
        while (inFile >> item.name >> item.value >> item.weight) {
            std::cout << item.name << " (Value: " << item.value 
                      << ", Weight: " << item.weight << ")" << std::endl;
        }
        inFile.close();
    }

    // Append
    std::ofstream appendFile("inventory.txt", std::ios::app);
    if (appendFile.is_open()) {
        appendFile << "Bow 35 2" << std::endl;
        appendFile.close();
        std::cout << "\n✅ Appended Bow" << std::endl;
    }

    // Read again
    inFile.open("inventory.txt");
    if (inFile.is_open()) {
        Item item;
        std::cout << "\n--- Final Inventory ---" << std::endl;
        while (inFile >> item.name >> item.value >> item.weight) {
            std::cout << item.name << " (Value: " << item.value 
                      << ", Weight: " << item.weight << ")" << std::endl;
        }
        inFile.close();
    }

    // Check existence
    std::ifstream check("inventory.txt");
    if (check.is_open()) {
        std::cout << "\n✅ File exists!" << std::endl;
        check.close();
    }

    return 0;
}
